#include <bits/stdc++.h>
using namespace std;
char sss[201];
int m[618], s[5];
bool ok[5][5][5], dp[201][201][5], flag;
int main () {
    m['W'] = 1;
	m['I'] = 2;
	m['N'] = 3;
	m['G'] = 4; 
    for (int i = 1; i <= 4; ++i) {
    	cin >> s[i];
	}
    for (int i = 1; i <= 4; ++i) {
        for (int j = 1; j <= s[i]; ++j) {
            char a, b;
            cin >> a >> b;
            ok[m[a]][m[b]][i] = 1;
        }
    }
    cin >> sss;
    int n = strlen (sss);
    for (int i = 1; i <= n; ++i) {
        dp[i][i][m[sss[i - 1]]] = 1;
    }
    for (int l = 2; l <= n; l++) {
        for (int i = 1; i <= n - l + 1; i++) {
            int j = i + l - 1;
            for (int k = i; k < j; k++) {
                for (int x = 1; x <= 4; x++) {
                    for (int y = 1; y <= 4; y++) {
                        for (int z = 1; z <= 4; z++) {
                            if (dp[i][k][y] && dp[k + 1][j][z] && ok[y][z][x]) {
                                dp[i][j][x] = 1;
                            }
                        }
                    }
                }
            }
        }
    }
    if (dp[1][n][1]) {
		flag = 1;
		cout << 'W';
	}
    if (dp[1][n][2]) {
		flag = 1;
		cout << 'I';
	}
    if (dp[1][n][3]) {
    	flag = 1;
		cout << 'N';
	}
    if (dp[1][n][4]) {
		flag = 1;
		cout << 'G';
	}
    if (!flag) {
    	cout << "The name is wrong!";
	}
    return 0;
}
